package io.bootify.vcore.domain;

import io.bootify.vcore.model.ArtstyleType;
import jakarta.persistence.*;
import io.bootify.vcore.model.CommissionType;

@Entity
@Table(name = "commission_requests")
public class CommissionRequest {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    private String senderName;

    @Column(nullable = false)
    private String senderEmail;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private CommissionType commissionType;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private ArtstyleType artstyleType;

    @Column(length = 2000)
    private String additionalNotes;

    // Constructors
    public CommissionRequest() {}

    public CommissionRequest(String senderName, String senderEmail, CommissionType commissionType, ArtstyleType artstyleType, String additionalNotes) {
        this.senderName = senderName;
        this.senderEmail = senderEmail;
        this.commissionType = commissionType;
        this.artstyleType = artstyleType;
        this.additionalNotes = additionalNotes;
    }


    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getSenderName() { return senderName; }
    public void setSenderName(String senderName) { this.senderName = senderName; }

    public String getSenderEmail() { return senderEmail; }
    public void setSenderEmail(String senderEmail) { this.senderEmail = senderEmail; }

    public CommissionType getCommissionType() { return commissionType; }
    public void setCommissionType(CommissionType commissionType) { this.commissionType = commissionType; }

    public ArtstyleType getArtstyleType() { return artstyleType; }
    public void setArtstyleType(ArtstyleType artstyleType) { this.artstyleType = artstyleType; }


    public String getAdditionalNotes() { return additionalNotes; }
    public void setAdditionalNotes(String additionalNotes) { this.additionalNotes = additionalNotes; }
}

package io.bootify.vcore.domain;

import io.bootify.vcore.model.ArtstyleType;
import jakarta.persistence.*;
import io.bootify.vcore.model.CommissionType;

@Entity
@Table(name = "commission_requests")
public class CommissionRequest {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    private String senderName;

    @Column(nullable = false)
    private String senderEmail;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private CommissionType commissionType;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, columnDefinition = "varchar(255) default 'SKETCH'")
    private ArtstyleType artstyleType;

    @Column(length = 2000)
    private String additionalNotes;

    // Constructors
    public CommissionRequest() {}

    public CommissionRequest(String senderName, String senderEmail, CommissionType commissionType, ArtstyleType artstyleType, String additionalNotes) {
        this.senderName = senderName;
        this.senderEmail = senderEmail;
        this.commissionType = commissionType;
        this.artstyleType = artstyleType;
        this.additionalNotes = additionalNotes;
    }


    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getSenderName() { return senderName; }
    public void setSenderName(String senderName) { this.senderName = senderName; }

    public String getSenderEmail() { return senderEmail; }
    public void setSenderEmail(String senderEmail) { this.senderEmail = senderEmail; }

    public CommissionType getCommissionType() { return commissionType; }
    public void setCommissionType(CommissionType commissionType) { this.commissionType = commissionType; }

    public ArtstyleType getArtstyleType() { return artstyleType; }
    public void setArtstyleType(ArtstyleType artstyleType) { this.artstyleType = artstyleType; }


    public String getAdditionalNotes() { return additionalNotes; }
    public void setAdditionalNotes(String additionalNotes) { this.additionalNotes = additionalNotes; }
}

package io.bootify.vcore.service;

import io.bootify.vcore.domain.CommissionRequest;
import io.bootify.vcore.model.CommissionRequestDTO;
import io.bootify.vcore.repos.CommissionRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.mail.SimpleMailMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.stream.Collectors;

@Service
public class CommissionService {

    private final CommissionRepository commissionRepository;
    private final JavaMailSender mailSender;

    // We can inject the site owner's email from application properties, 
    // or fallback to a default value if not set.
    @Value("${app.owner.email:owner@example.com}")
    private String ownerEmail;

    public CommissionService(CommissionRepository commissionRepository, JavaMailSender mailSender) {
        this.commissionRepository = commissionRepository;
        this.mailSender = mailSender;
    }

    public String createCommission(CommissionRequestDTO dto) {

        CommissionRequest entity = new CommissionRequest(
                dto.getSenderName(),
                dto.getSenderEmail(),
                dto.getCommissionType(),
                dto.getArtstyleType(),
                dto.getAdditionalNotes()
        );


        commissionRepository.save(entity);

        sendEmailToOwner(dto);
        sendEmailToSender(dto);

        return "Commission submitted successfully!";
    }


    public List<CommissionRequestDTO> getAllCommissions() {
        return commissionRepository.findAll().stream().map(entity -> {
            CommissionRequestDTO dto = new CommissionRequestDTO();
            dto.setSenderName(entity.getSenderName());
            dto.setSenderEmail(entity.getSenderEmail());
            dto.setCommissionType(entity.getCommissionType());
            dto.setArtstyleType(entity.getArtstyleType());
            dto.setAdditionalNotes(entity.getAdditionalNotes());
            return dto;
        }).collect(Collectors.toList());
    }

    private void sendEmailToOwner(CommissionRequestDTO dto) {
        SimpleMailMessage message = new SimpleMailMessage();
        message.setTo(ownerEmail);
        message.setSubject("New Art Commission Request!");
        message.setText("You received a new commission request.\n\n" +
                "From: " + dto.getSenderName() + " (" + dto.getSenderEmail() + ")\n" +
                "Type: " + dto.getCommissionType().getDisplayName() + "\n" +
                "Style: " + dto.getArtstyleType().getDisplayName() + "\n" +
                "Notes: " + dto.getAdditionalNotes());

        try {
            mailSender.send(message);
        } catch (Exception e) {
            System.err.println("Could not send email to owner: " + e.getMessage());
        }
    }

    private void sendEmailToSender(CommissionRequestDTO dto) {
        SimpleMailMessage message = new SimpleMailMessage();
        message.setTo(dto.getSenderEmail());
        message.setSubject("Copy of your Art Commission Request");
        message.setText("Hello " + dto.getSenderName() + ",\n\n" +
                "Thank you for requesting an art commission! Here is a copy of your request:\n\n" +
                "Type: " + dto.getCommissionType().getDisplayName() + "\n" +
                "Style: " + dto.getArtstyleType().getDisplayName() + "\n" +
                "Notes: " + dto.getAdditionalNotes() + "\n\n" +
                "I will get back to you soon!");

        try {
            mailSender.send(message);
        } catch (Exception e) {
            System.err.println("Could not send email to sender: " + e.getMessage());
        }
    }
}

package io.bootify.vcore.service;

import io.bootify.vcore.domain.CommissionRequest;
import io.bootify.vcore.model.CommissionRequestDTO;
import io.bootify.vcore.repos.CommissionRepository;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.mail.SimpleMailMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.stream.Collectors;

@Service
public class CommissionService {

    private final CommissionRepository commissionRepository;
    private final JavaMailSender mailSender;

    // We can inject the site owner's email from application properties, 
    // or fallback to a default value if not set.
    @Value("${app.owner.email:owner@example.com}")
    private String ownerEmail;

    public CommissionService(CommissionRepository commissionRepository, JavaMailSender mailSender) {
        this.commissionRepository = commissionRepository;
        this.mailSender = mailSender;
    }

    public String createCommission(CommissionRequestDTO dto) {

        CommissionRequest entity = new CommissionRequest(
                dto.getSenderName(),
                dto.getSenderEmail(),
                dto.getCommissionType(),
                dto.getArtstyleType(),
                dto.getAdditionalNotes()
        );


        commissionRepository.save(entity);

        sendEmailToOwner(dto);
        sendEmailToSender(dto);

        return "Commission submitted successfully!";
    }


    public List<CommissionRequestDTO> getAllCommissions() {
        return commissionRepository.findAll().stream().map(entity -> {
            CommissionRequestDTO dto = new CommissionRequestDTO();
            dto.setSenderName(entity.getSenderName());
            dto.setSenderEmail(entity.getSenderEmail());
            dto.setCommissionType(entity.getCommissionType());
            dto.setArtstyleType(entity.getArtstyleType());
            dto.setAdditionalNotes(entity.getAdditionalNotes());
            return dto;
        }).collect(Collectors.toList());
    }

    private void sendEmailToOwner(CommissionRequestDTO dto) {
        SimpleMailMessage message = new SimpleMailMessage();
        message.setTo(ownerEmail);
        message.setSubject("New Art Commission Request!");
        message.setText("You received a new commission request.\n\n" +
                "From: " + dto.getSenderName() + " (" + dto.getSenderEmail() + ")\n" +
                "Type: " + dto.getCommissionType().getDisplayName() + "\n" +
                "Style: " + dto.getArtstyleType().getDisplayName() + "\n" +
                "Notes: " + dto.getAdditionalNotes());

        try {
            mailSender.send(message);
        } catch (Exception e) {
            // Log error in a real app, ignoring for simplicity
            System.err.println("Could not send email to owner: " + e.getMessage());
        }
    }

    private void sendEmailToSender(CommissionRequestDTO dto) {
        SimpleMailMessage message = new SimpleMailMessage();
        message.setTo(dto.getSenderEmail());
        message.setSubject("Copy of your Art Commission Request");
        message.setText("Hello " + dto.getSenderName() + ",\n\n" +
                "Thank you for requesting an art commission! Here is a copy of your request:\n\n" +
                "Type: " + dto.getCommissionType().getDisplayName() + "\n" +
                "Style: " + dto.getArtstyleType().getDisplayName() + "\n" +
                "Notes: " + dto.getAdditionalNotes() + "\n\n" +
                "I will get back to you soon!");

        try {
            mailSender.send(message);
        } catch (Exception e) {
            System.err.println("Could not send email to sender: " + e.getMessage());
        }
    }
}
